using Avalonia;
using Avalonia.Controls;
using Avalonia.Headless.XUnit;
using Avalonia.Media.Imaging;
using Avalonia.Media;
using Notey.App.Views;

namespace Notey.Tests;

public sealed class ImagePreviewWindowTests
{
    [Fact]
    public void GetConstrainedImageSize_scales_large_images_to_fit_available_space()
    {
        var size = ImagePreviewWindow.GetConstrainedImageSize(new Size(600, 300), new Size(300, 180));

        Assert.Equal(300d, size.Width);
        Assert.Equal(150d, size.Height);
    }

    [AvaloniaFact]
    public void CreatePreviewContent_uses_a_direct_image_without_scrollviewer()
    {
        using var bitmap = CreateBitmap();
        var preview = Assert.IsType<Border>(ImagePreviewWindow.CreatePreviewContent(bitmap, string.Empty));
        var image = Assert.IsType<Image>(preview.Child);

        Assert.Equal(Stretch.Uniform, image.Stretch);
        Assert.Equal(StretchDirection.DownOnly, image.StretchDirection);
    }

    private static Bitmap CreateBitmap()
    {
        var bytes = Convert.FromBase64String(PngBase64);
        return new Bitmap(new MemoryStream(bytes, writable: false));
    }

    private const string PngBase64 =
        "";
}
